# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import json
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

# Connect to the MySQL database
conn = pymysql.connect(host='localhost', user='username', password='password', db='db_name')
cur = conn.cursor()

@app.route('/search', methods=['GET'])
def search():
    # Get the search parameters from the HTTP request
    params = request.args
    query = "SELECT * FROM table_name WHERE "
    for param in params:
        if param == 'query':
            query += f"title LIKE '%{params[param]}%' AND "
        elif param == 'category':
            query += f"category='{params[param]}' AND "
        else:
            query += f"{param}='{params[param]}' AND "
    # Remove the trailing "AND " from the query string
    query = query[:-4] + ";"
    cur.execute(query)
    results = cur.fetchall()
    conn.close()
    return jsonify(results)